import os, sys, xml.etree.ElementTree as ET
policy=os.environ.get('AUTOMATESTIG_TOMCAT_CONNECTOR_ADDRESSES','').strip()
if not policy:
    raise SystemExit(0)
allowed={item.strip() for item in policy.split(',') if item.strip()}
if not allowed:
    raise SystemExit(0)
path=os.path.join(os.environ.get('CATALINA_BASE','/opt/tomcat'),'conf','server.xml')
try:
    root=ET.parse(path).getroot()
except Exception:
    raise SystemExit(0)
connectors=list(root.iter('Connector'))
if connectors and all(connector.attrib.get('address','').strip() in allowed for connector in connectors):
    print('Compliant', end='')
PY
